import { Diagram } from 'diagrams-js';
import { EC2, Lambda } from 'diagrams-js/aws/compute.js';
import { RDS } from 'diagrams-js/aws/database.js';
import { S3 } from 'diagrams-js/aws/storage.js';

// Create initial diagram
let diagram = Diagram('Web Architecture', {
  direction: 'TB',
  theme: 'pastel'
});

const web = diagram.add(EC2('Web Server'));
const api = diagram.add(Lambda('API'));
const db = diagram.add(RDS('Database'));
const storage = diagram.add(S3('Storage'));

web.to(api).to(db);
api.to(storage);

// Render initial diagram
async function renderDiagram() {
  const svg = await diagram.render();
  document.getElementById('diagram').innerHTML = svg;
}

await renderDiagram();

// Export to JSON
document.getElementById('export-btn').addEventListener('click', () => {
  const json = diagram.toJSON();
  const jsonStr = JSON.stringify(json, null, 2);
  document.getElementById('json-output').textContent = jsonStr;
  console.log('Exported JSON:', json);
});

// Import from JSON
document.getElementById('import-btn').addEventListener('click', async () => {
  const jsonExample = {
    "name": "Microservices Architecture",
    "direction": "LR",
    "theme": "blues",
    "nodes": [
      {
        "id": "gateway",
        "label": "API Gateway",
        "provider": "aws",
        "service": "network",
        "type": "APIGateway"
      },
      {
        "id": "auth",
        "label": "Auth Service",
        "provider": "aws",
        "service": "compute",
        "type": "Lambda"
      },
      {
        "id": "users",
        "label": "Users Service",
        "provider": "aws",
        "service": "compute",
        "type": "Lambda"
      },
      {
        "id": "orders",
        "label": "Orders Service",
        "provider": "aws",
        "service": "compute",
        "type": "Lambda"
      },
      {
        "id": "db",
        "label": "DynamoDB",
        "provider": "aws",
        "service": "database",
        "type": "Dynamodb"
      },
      {
        "id": "cache",
        "label": "ElastiCache",
        "provider": "aws",
        "service": "database",
        "type": "ElastiCache"
      }
    ],
    "edges": [
      { "from": "gateway", "to": "auth", "label": "auth" },
      { "from": "gateway", "to": "users" },
      { "from": "gateway", "to": "orders" },
      { "from": "users", "to": "db" },
      { "from": "orders", "to": "db" },
      { "from": "users", "to": "cache" },
      { "from": "orders", "to": "cache" }
    ]
  };

  // Show the JSON
  document.getElementById('json-output').textContent = JSON.stringify(jsonExample, null, 2);

  // Import it - icons resolved automatically!
  diagram = await Diagram.fromJSON(jsonExample);
  await renderDiagram();

  console.log('Imported from JSON with auto-resolved icons!');
});

// Clear
document.getElementById('clear-btn').addEventListener('click', () => {
  document.getElementById('json-output').textContent = '';
});
